    <div class="ex3">테스트</div>
    <hr>
    <div id="touchSlider11">
	<ul>
		<li>content 1</li>
		<li>content 2</li>
		<li>content 3</li>
		<li>content 4</li>
	</ul>
</div>
  </div>
</template>

<script>
    import $ from 'jquery'
    import touchSlider from 'jquery.touchslider' //eslint-disable-line no-unused-vars

export default {
    mounted() { //인스턴스에 부착되고 호출되는 상태
        $('#ex1').click(function(){
            alert('안녕하세요')
            $(this).next('span').text('인사')
        })
        $('#ex2').click(function(){
            $('.ex3').css({color : 'red', backgroundColor : 'yellow', width: '100px',
            height : '100px'})
        })
        $('#touchSlider11').touchSlider({
            speed:1000,
            autoplay: {
            enable: true,
            pauseHover: true,
            addHoverTarget: '',
            interval: 3500
	}
});

        

    },

}
