<style>
.ts-controls { height: 36px; background:#f5f5f5; position: relative; overflow: hidden; }
.ts-prev { display: none; }
.ts-next { display: none; }

.ts-paging { width:100%; text-align:center; }
.ts-paging-btn { display:inline-block; width:15px; height:15; border-radius:50%; 
    border: 1px solid #333; margin-left: 7px; font-size: 0;
    background:#3399CC; overflow: hidden; }
